sqlMap.update:
CREATE TEMPORARY TABLE IF NOT EXISTS quality SELECT c1.questionScore AS projectScore, c3.questionScore AS engScore, t4.evaluationScore ,a.projectId , IFNULL(t3.column001, "") as column001, t4.createdTime , t3.`column011`, t3.`column012`, t3.`columno12_readonly` FROM (SELECT MAX(aa.id) AS id, aa.projectId, aa.projectCode, COUNT(aa.id) AS times FROM pm_cl_evaluation_header aa WHERE aa.evaluationType = 3 AND aa.status = 1 GROUP BY aa.projectCode) a LEFT JOIN pm_cl_quesnaire_result_header b ON a.id=b.evaluationHeaderId AND b.status=1 LEFT JOIN (SELECT quesnaireTemplateHeaderId,quesnaireResultHeaderId,quesTypeForCB,SUM(questionScore) AS questionScore FROM pm_cl_quesnaire_result_line GROUP BY quesnaireResultHeaderId,quesTypeForCB) c1 ON b.id=c1.quesnaireResultHeaderId AND c1.quesTypeForCB=10
LEFT JOIN (SELECT quesnaireTemplateHeaderId,quesnaireResultHeaderId,quesTypeForCB,SUM(questionScore) AS questionScore FROM pm_cl_quesnaire_result_line GROUP BY quesnaireResultHeaderId,quesTypeForCB) c3 ON b.id=c3.quesnaireResultHeaderId AND c3.quesTypeForCB=30
JOIN pm_project_header t3 ON a.projectId = t3.projectId AND t3.projectState = '100' LEFT JOIN ( SELECT t1.`evaluationScore` , t2.`column001` , t2.`projectId`,t1.`createdTime` FROM pm_cl_evaluation_header t1 JOIN pm_project_header t2 ON t1.`projectId` = t2.`projectId` AND t2.projectState = '100' JOIN (SELECT MAX(t1.`id`) AS maxId FROM pm_cl_evaluation_header t1 JOIN pm_cl_quesnaire_result_header t2 ON t1.`id` = t2.`evaluationHeaderId` AND quesnaireTemplateHeaderId = 2 GROUP BY projectId ) t ON t1.id = t.maxId ) t4 ON a.projectId = t4.projectId GROUP BY a.projectCode;

sqlMap.select:
SELECT (SUM(projectScore)+SUM(engScore) + SUM(evaluationScore)) /COUNT(*) as avgCloseScore , COUNT(*) AS projectSize , 'total' as officeCode FROM quality where createdTime > #quarterStartTime#
( ( (column011 != #projectCategory# OR column011 IS NULL)
( column012 != #isALl# OR columno12_readonly != #isALl# )
)
( column012 = #implWay# OR (columno12_readonly = #implWay#) )
)

SELECT 0 AS avgCloseScore, 0 AS projectSize, departmentNum AS officeCode FROM fnd_department WHERE isparam = 1 AND NOT EXISTS ( SELECT 1 FROM quality WHERE column001 = departmentNum and createdTime > #quarterStartTime#
( ( (column011 != #projectCategory# OR column011 IS NULL)
( column012 != #isALl# OR columno12_readonly != #isALl# )
)
( column012 = #implWay# OR (columno12_readonly = #implWay#) )
)
)

SELECT 0 AS specificValue, 0 AS conditionValue, 0 AS totalValue, departmentNum AS officeCode , NOW() AS settingTime , departmentName AS officeName FROM fnd_department WHERE isparam = 1 AND NOT EXISTS (SELECT 1 FROM quality WHERE column001 = departmentNum AND createdTime > #quarterStartTime#
( ( (column011 != #projectCategory# OR column011 IS NULL)
( column012 != #isALl# OR columno12_readonly != #isALl# )
)
( column012 = #implWay# OR (columno12_readonly = #implWay#) )
)
)


	SELECT  COUNT(*) FROM pm_project_header t1
	JOIN pm_project_state t2 ON t1.`projectId` = t2.`projectId`
	WHERE t1.projectState IN (30,31,32) AND t1.effectiveTo IS NULL AND t2.`shipmentState` = -1;
